const input    = $input.first().json;
const msg      = input.message || {};
const text     = msg.text || '';

// ── Chat ID: handle string, number, or missing ──
const rawChatId = input.chat?.id || input.chat_id || msg.chat?.id || '';
const chatId    = String(rawChatId).trim(); // normalise to string

// ── User name: handle emoji, missing, nested differently ──
const rawName = 
  input.user?.name ||           // your structure: { user: { name: "🫅" } }
  input.user?.first_name ||     // alternative structure
  input.user?.username ||       // fallback to username handle
  msg.from?.first_name ||       // standard Telegram structure
  msg.from?.username ||         // standard Telegram username
  '';                           // empty if nothing found

// Clean the name — strip excess whitespace but keep emojis intact
const userName = rawName.trim() || 'there';

// ── Determine display name for responses ──
// If name is emoji-only or very short, use generic greeting
const isEmojiOnly = rawName.length > 0 && !/[a-zA-Z0-9]/.test(rawName);
const displayName = isEmojiOnly ? rawName : (userName || 'there');

// ── Validate text ──
if (!text || text.trim() === '') {
  return [{
    json: {
      skip: true,
      chat_id: chatId,
      user_name: userName,
      display_name: displayName,
      fallback_message: `Hi ${displayName}! I can only process text messages. Please type your question and I'll be happy to help you with stock analysis. 📊`
    }
  }];
}

return [{
  json: {
    skip: false,
    text: text.trim(),
    chat_id: chatId,
    user_name: userName,
    display_name: displayName
  }
}];

const data = $input.first().json;

// ── INPUTS ──────────────────────────────────────────────
const meta      = data.meta || {};
const timeSeries = data.values || [];
const stats     = data.statistics || {};
const val       = stats.valuations_metrics || {};
const fin       = stats.financials || {};
const inc       = fin.income_statement || {};
const bal       = fin.balance_sheet || {};
const cf        = fin.cash_flow || {};
const stk       = stats.stock_statistics || {};
const prc       = stats.stock_price_summary || {};
const div       = stats.dividends_and_splits || {};

const ticker        = meta.symbol || 'UNKNOWN';
const companyName   = meta.name || ticker;
const positionSize  = $input.first().json.positionSize || 10000;
const currentPrice  = parseFloat(timeSeries[0]?.close) || 0;

// ── DAILY RETURNS ────────────────────────────────────────
const returns = [];
for (let i = 1; i < timeSeries.length; i++) {
  const curr = parseFloat(timeSeries[i-1].close);
  const prev = parseFloat(timeSeries[i].close);
  if (prev > 0) returns.push(((curr - prev) / prev) * 100);
}

// ── VOLATILITY (Annualised) ──────────────────────────────
const mean = returns.reduce((s, r) => s + r, 0) / returns.length;
const variance = returns.reduce((s, r) => s + Math.pow(r - mean, 2), 0) / returns.length;
const dailyVol = Math.sqrt(variance);
const annualVol = dailyVol * Math.sqrt(252);

// ── MAXIMUM DRAWDOWN ─────────────────────────────────────
let peak = parseFloat(timeSeries[0]?.close) || 0;
let maxDrawdown = 0;
let drawdownStart = timeSeries[0]?.datetime;
let drawdownEnd = timeSeries[0]?.datetime;
let tempPeakDate = timeSeries[0]?.datetime;

timeSeries.forEach(day => {
  const price = parseFloat(day.close);
  if (price > peak) {
    peak = price;
    tempPeakDate = day.datetime;
  }
  const dd = ((peak - price) / peak) * 100;
  if (dd > maxDrawdown) {
    maxDrawdown = dd;
    drawdownStart = tempPeakDate;
    drawdownEnd = day.datetime;
  }
});

// ── VALUE AT RISK (95%, 1-day) ───────────────────────────
const sortedReturns = [...returns].sort((a, b) => a - b);
const varIndex = Math.floor(sortedReturns.length * 0.05);
const var95Pct  = Math.abs(sortedReturns[varIndex] || 0);
const var95Dollar = (positionSize * var95Pct) / 100;

// ── 52-WEEK POSITIONING ──────────────────────────────────
const low52  = prc.fifty_two_week_low || 0;
const high52 = prc.fifty_two_week_high || 0;
const pctFrom52Low  = (((currentPrice - low52) / low52) * 100).toFixed(2);
const pctFrom52High = (((high52 - currentPrice) / high52) * 100).toFixed(2);
const rangePosition = (((currentPrice - low52) / (high52 - low52)) * 100).toFixed(1);

// ── MOVING AVERAGE SIGNALS ───────────────────────────────
const ma50  = prc.day_50_ma || 0;
const ma200 = prc.day_200_ma || 0;
const aboveMa50  = currentPrice > ma50;
const aboveMa200 = currentPrice > ma200;
const goldenCross = ma50 > ma200; // bullish long-term signal

// ── SHORT INTEREST ───────────────────────────────────────
const shortPct = (stk.short_percent_of_shares_outstanding * 100).toFixed(2);
const shortRatio = stk.short_ratio || 0;
const highShortInterest = stk.short_percent_of_shares_outstanding > 0.05;

// ── FINANCIAL HEALTH METRICS ─────────────────────────────
const debtToEquity   = bal.total_debt_to_equity_mrq || 0;
const currentRatio   = bal.current_ratio_mrq || 0;
const profitMargin   = (fin.profit_margin * 100).toFixed(2);
const operatingMargin = (fin.operating_margin * 100).toFixed(2);
const grossMargin    = (fin.gross_margin * 100).toFixed(2);
const roe            = (fin.return_on_equity_ttm * 100).toFixed(2);
const roa            = (fin.return_on_assets_ttm * 100).toFixed(2);
const fcf            = cf.levered_free_cash_flow_ttm || 0;
const ocf            = cf.operating_cash_flow_ttm || 0;
const cashVsDebt     = bal.total_cash_mrq - bal.total_debt_mrq;

// ── VALUATION RISK ───────────────────────────────────────
const trailingPE  = val.trailing_pe || 0;
const forwardPE   = val.forward_pe || 0;
const pegRatio    = val.peg_ratio || 0;
const ptb         = val.price_to_book_mrq || 0;
const evEbitda    = val.enterprise_to_ebitda || 0;

// ── COMPOSITE RISK SCORE (1-10) ──────────────────────────
// Volatility: >40% annualised = 10, <10% = 1
const volatilityScore = Math.min(Math.max((annualVol / 4), 1), 10);

// Drawdown: >40% = 10, <5% = 1
const drawdownScore = Math.min(Math.max((maxDrawdown / 4), 1), 10);

// Beta: far from 1 = higher risk
const beta = prc.beta || 1;
const betaScore = Math.min(Math.max(Math.abs(beta - 1) * 5 + 1, 1), 10);

// Valuation risk: high PE + high PEG = overvaluation risk
const valuationScore = Math.min(Math.max((trailingPE / 10) + (pegRatio > 2 ? 2 : 0), 1), 10);

// Leverage risk: high debt-to-equity
const leverageScore = Math.min(Math.max(debtToEquity / 20, 1), 10);

// Composite (weighted)
const riskScore = Math.round(
  (volatilityScore * 0.25) +
  (drawdownScore   * 0.25) +
  (betaScore       * 0.20) +
  (valuationScore  * 0.20) +
  (leverageScore   * 0.10)
);

const riskLabel = riskScore <= 3 ? '🟢 LOW RISK' :
                  riskScore <= 5 ? '🟡 MODERATE RISK' :
                  riskScore <= 7 ? '🟠 ELEVATED RISK' : '🔴 HIGH RISK';

// ── STOP-LOSS RECOMMENDATION ─────────────────────────────
const stopLoss = (currentPrice * (1 - (maxDrawdown / 200))).toFixed(2);
const stopLossPct = ((currentPrice - stopLoss) / currentPrice * 100).toFixed(2);

// ── POSITION SIZING ──────────────────────────────────────
const positionGuide = riskScore <= 3 ? '10–15% of portfolio' :
                      riskScore <= 5 ? '5–10% of portfolio' :
                      riskScore <= 7 ? '3–5% of portfolio' : '1–3% of portfolio (high risk)';

// ── FORMATTED REPORT ─────────────────────────────────────
const formatted = `
RISK ANALYSIS REPORT — ${ticker} (${companyName})
Generated: ${new Date().toISOString()}

═══════════════════════════════════════════════════
POSITION & PRICE CONTEXT
═══════════════════════════════════════════════════
Current Price:      $${currentPrice}
Position Size:      $${positionSize.toLocaleString()}
52-Week Low:        $${low52}  (+${pctFrom52Low}% current)
52-Week High:       $${high52}  (-${pctFrom52High}% current)
Range Position:     ${rangePosition}% between 52w low and high

50-Day MA:          $${ma50}  ${aboveMa50 ? '✅ Price ABOVE (bullish)' : '⚠️ Price BELOW (bearish)'}
200-Day MA:         $${ma200}  ${aboveMa200 ? '✅ Price ABOVE (bullish)' : '⚠️ Price BELOW (bearish)'}
MA Cross Signal:    ${goldenCross ? '✅ Golden Cross (50MA > 200MA) — Bullish' : '⚠️ Death Cross (50MA < 200MA) — Bearish'}

═══════════════════════════════════════════════════
OVERALL RISK SCORE: ${riskScore}/10 — ${riskLabel}
═══════════════════════════════════════════════════

Component Breakdown:
  Volatility Risk:   ${volatilityScore.toFixed(1)}/10
  Drawdown Risk:     ${drawdownScore.toFixed(1)}/10
  Beta Risk:         ${betaScore.toFixed(1)}/10
  Valuation Risk:    ${valuationScore.toFixed(1)}/10
  Leverage Risk:     ${leverageScore.toFixed(1)}/10

═══════════════════════════════════════════════════
PRICE RISK METRICS
═══════════════════════════════════════════════════
Annualised Volatility:    ${annualVol.toFixed(2)}%
Daily Volatility:         ${dailyVol.toFixed(2)}%

Maximum Drawdown:         ${maxDrawdown.toFixed(2)}%
  Peak date:              ${drawdownStart}
  Trough date:            ${drawdownEnd}

Value at Risk (95%, 1d):  $${var95Dollar.toFixed(2)}  (${var95Pct.toFixed(2)}% of position)
  Interpretation: On 95% of trading days, loss will not exceed $${var95Dollar.toFixed(2)}

═══════════════════════════════════════════════════
VALUATION RISK
═══════════════════════════════════════════════════
Trailing P/E:       ${trailingPE.toFixed(2)}
Forward P/E:        ${forwardPE.toFixed(2)}  ${forwardPE < trailingPE ? '✅ Earnings growth expected' : '⚠️ Earnings expected to decline'}
PEG Ratio:          ${pegRatio.toFixed(2)}  ${pegRatio < 1 ? '✅ Undervalued relative to growth' : pegRatio < 2 ? '⚠️ Fairly valued' : '🔴 Potentially overvalued'}
Price-to-Book:      ${ptb.toFixed(2)}
EV/EBITDA:          ${evEbitda.toFixed(2)}

═══════════════════════════════════════════════════
FINANCIAL HEALTH
═══════════════════════════════════════════════════
Gross Margin:       ${grossMargin}%
Operating Margin:   ${operatingMargin}%
Net Profit Margin:  ${profitMargin}%
Return on Equity:   ${roe}%
Return on Assets:   ${roa}%

Operating Cash Flow:    $${(ocf / 1e9).toFixed(2)}B
Free Cash Flow:         $${(fcf / 1e9).toFixed(2)}B
Total Cash:             $${(bal.total_cash_mrq / 1e9).toFixed(2)}B
Total Debt:             $${(bal.total_debt_mrq / 1e9).toFixed(2)}B
Net Cash Position:      ${cashVsDebt >= 0 ? '+' : ''}$${(cashVsDebt / 1e9).toFixed(2)}B  ${cashVsDebt >= 0 ? '✅ Net cash positive' : '⚠️ Net debt position'}
Debt-to-Equity:         ${debtToEquity.toFixed(2)}
Current Ratio:          ${currentRatio.toFixed(2)}  ${currentRatio >= 1 ? '✅ Adequate liquidity' : '⚠️ Liquidity concern'}

═══════════════════════════════════════════════════
MARKET SENTIMENT INDICATORS
═══════════════════════════════════════════════════
Beta:                   ${beta}  ${beta > 1.2 ? '⚠️ More volatile than market' : beta < 0.8 ? '✅ Defensive — less volatile than market' : '✅ Moves broadly with market'}
Short Interest:         ${shortPct}%  ${highShortInterest ? '⚠️ Elevated short interest' : '✅ Low short interest'}
Short Ratio:            ${shortRatio} days to cover
Institutional Ownership: ${(stk.percent_held_by_institutions * 100).toFixed(1)}%  ${stk.percent_held_by_institutions > 0.6 ? '✅ Strong institutional backing' : '⚠️ Low institutional conviction'}
Insider Ownership:      ${(stk.percent_held_by_insiders * 100).toFixed(2)}%

Dividend Yield:         ${(div.forward_annual_dividend_yield * 100).toFixed(2)}%
Payout Ratio:           ${(div.payout_ratio * 100).toFixed(1)}%  ${div.payout_ratio < 0.5 ? '✅ Sustainable dividend' : '⚠️ High payout ratio'}

═══════════════════════════════════════════════════
RISK MANAGEMENT RECOMMENDATIONS
═══════════════════════════════════════════════════
Suggested Stop-Loss:    $${stopLoss}  (${stopLossPct}% below current price)
Max Downside to Stop:   $${((currentPrice - stopLoss) * (positionSize / currentPrice)).toFixed(2)} on $${positionSize.toLocaleString()} position

Recommended Position Size: ${positionGuide}

Diversification Note:
${riskScore > 6 ? '🔴 CRITICAL — Ensure strong sector diversification. Do not concentrate.' :
  riskScore > 3 ? '🟡 Standard diversification across sectors recommended.' :
  '🟢 Well-suited as a core holding with standard diversification.'}
`;

return {
  json: {
    ticker,
    companyName,
    riskScore,
    riskLabel,
    annualizedVolatility: parseFloat(annualVol.toFixed(2)),
    dailyVolatility: parseFloat(dailyVol.toFixed(2)),
    maxDrawdown: parseFloat(maxDrawdown.toFixed(2)),
    drawdownPeriod: { start: drawdownStart, end: drawdownEnd },
    var95Percent: parseFloat(var95Pct.toFixed(2)),
    var95Dollar: parseFloat(var95Dollar.toFixed(2)),
    beta,
    trailingPE,
    forwardPE,
    pegRatio,
    profitMargin: parseFloat(profitMargin),
    operatingMargin: parseFloat(operatingMargin),
    freeCashFlow: fcf,
    netCashPosition: cashVsDebt,
    shortInterestPct: parseFloat(shortPct),
    institutionalOwnership: parseFloat((stk.percent_held_by_institutions * 100).toFixed(1)),
    stopLoss: parseFloat(stopLoss),
    positionGuide,
    rangePosition: parseFloat(rangePosition),
    aboveMa50,
    aboveMa200,
    goldenCross,
    formatted
  }
};

const input = $input.first().json;

// Handle Chat Trigger (chatInput) OR workflow trigger (tickers field)
const raw = input.chatInput || input.tickers || input.message || input.text || '';

// Extract ticker symbols — handles:
// "AAPL, TSLA, MSFT"         → comma separated
// "compare AAPL and TSLA"    → natural language
// "AAPL TSLA MSFT"           → space separated
const tickersInput = raw.toUpperCase();

// Pull out anything that looks like a stock ticker (1-5 capital letters)
const extracted = tickersInput.match(/\b[A-Z]{1,5}\b/g) || [];

// Filter out common English words that match ticker pattern
const stopWords = new Set([
  'A', 'I', 'AND', 'THE', 'FOR', 'VS', 'OR', 'ME', 'MY',
  'IN', 'ON', 'AT', 'TO', 'OF', 'IS', 'IT', 'BE', 'DO',
  'CAN', 'GET', 'HOW', 'ARE', 'WAS', 'HAS', 'HAD', 'BUT',
  'NOT', 'ALL', 'SO', 'IF', 'NO', 'UP', 'AN', 'AS', 'BY',
  'WITH', 'COMPARE', 'STOCK', 'STOCKS', 'PRICE', 'SHOW'
]);

const tickers = [...new Set(extracted.filter(t => !stopWords.has(t)))];

if (tickers.length === 0) {
  throw new Error('No stock tickers found. Please provide ticker symbols like: AAPL, TSLA, MSFT');
}

return tickers.map(ticker => ({
  json: { ticker }
}));

const items = $input.all();

const comparison = items.map(item => {
  const d = item.json;

  // Skip errors
  if (d.status === 'error' || d.code === 403) return null;

  const sym = d.symbol || d.meta?.symbol || 'N/A';

  // ── Price data — direct from root ──
  const price      = parseFloat(d.close || 0);
  const change     = parseFloat(d.percent_change || 0);
  const volume     = parseInt(d.volume || 0);
  const avgVolume  = parseInt(d.average_volume || 0);
  const fiftyTwo   = d.fifty_two_week || {};

  // ── RSI — from values[] array, first entry = most recent ──
  const rsi = d.values && d.values[0]?.rsi
    ? parseFloat(d.values[0].rsi).toFixed(2)
    : 'N/A';

  // ── Profile data — direct from root ──
  const sector   = d.sector   || 'N/A';
  const industry = d.industry || 'N/A';
  const ceo      = d.CEO      || d.ceo || 'N/A';
  const employees = parseInt(d.employees || 0);
  const description = d.description || '';
  const website  = d.website  || '';
  const exchange = d.exchange || 'N/A';
  const name     = d.name     || sym;

  return {
    symbol: sym,
    name,
    sector,
    industry,
    exchange,
    ceo,
    employees,
    description,
    website,
    price,
    change,
    volume,
    avgVolume,
    previousClose: parseFloat(d.previous_close || 0),
    open:  parseFloat(d.open  || 0),
    high:  parseFloat(d.high  || 0),
    low:   parseFloat(d.low   || 0),
    fiftyTwoWeekLow:  parseFloat(fiftyTwo.low  || 0),
    fiftyTwoWeekHigh: parseFloat(fiftyTwo.high || 0),
    rsi,
    isMarketOpen: d.is_market_open || false
  };
}).filter(Boolean);

// Sort by % change descending
comparison.sort((a, b) => b.change - a.change);

// ── Summary metrics ──
const bestPerformer  = comparison[0] || {};
const worstPerformer = comparison[comparison.length - 1] || {};
const perfGap        = (bestPerformer.change - worstPerformer.change).toFixed(2);

const validRSI = comparison.filter(s => s.rsi !== 'N/A');
const avgRSI   = validRSI.length > 0
  ? validRSI.reduce((sum, s) => sum + parseFloat(s.rsi), 0) / validRSI.length
  : 0;

const sectors    = [...new Set(comparison.map(s => s.sector).filter(s => s !== 'N/A'))];
const overbought = comparison.filter(s => s.rsi !== 'N/A' && parseFloat(s.rsi) > 70);
const oversold   = comparison.filter(s => s.rsi !== 'N/A' && parseFloat(s.rsi) < 30);

// ── Helper functions ──
const fmt = (n, d=2) => (!isNaN(n) && n !== null) ? Number(n).toFixed(d) : 'N/A';

const rsiSignal = (rsi) => {
  if (rsi === 'N/A') return 'N/A';
  const r = parseFloat(rsi);
  return r > 70 ? '🔴 Overbought' : r < 30 ? '🟢 Oversold' : r >= 50 ? '🟡 Neutral/Bullish' : '🟡 Neutral/Bearish';
};

const rangePosition = (price, low, high) => {
  if (!low || !high || high === low) return 'N/A';
  return (((price - low) / (high - low)) * 100).toFixed(0) + '%';
};

const fmtChange = (n) => (n >= 0 ? '+' : '') + fmt(n) + '%';

// ── Build report ──
const formatted = `
STOCK COMPARISON ANALYSIS
Generated: ${new Date().toISOString()}
Stocks Compared: ${comparison.map(s => s.symbol).join(' vs ')}
Market Status: ${comparison[0]?.isMarketOpen ? '🟢 Market Open' : '🔴 Market Closed'}

═══════════════════════════════════════════════════
PERFORMANCE SNAPSHOT
═══════════════════════════════════════════════════
${comparison.map((s, i) => `${i + 1}. ${s.symbol} — ${s.name}
   Price:        $${fmt(s.price)} (${fmtChange(s.change)})
   Open/High/Low: $${fmt(s.open)} / $${fmt(s.high)} / $${fmt(s.low)}
   Prev Close:   $${fmt(s.previousClose)}
   Sector:       ${s.sector} | ${s.industry}
   Exchange:     ${s.exchange}
   RSI (14):     ${s.rsi} — ${rsiSignal(s.rsi)}
   Volume:       ${(s.volume / 1e6).toFixed(2)}M (Avg: ${(s.avgVolume / 1e6).toFixed(1)}M)
   52-Week:      $${fmt(s.fiftyTwoWeekLow)} – $${fmt(s.fiftyTwoWeekHigh)}
   Range Pos:    ${rangePosition(s.price, s.fiftyTwoWeekLow, s.fiftyTwoWeekHigh)} of 52w range
   CEO:          ${s.ceo}
   Employees:    ${s.employees > 0 ? s.employees.toLocaleString() : 'N/A'}`
).join('\n\n')}

═══════════════════════════════════════════════════
RELATIVE PERFORMANCE SUMMARY
═══════════════════════════════════════════════════
Best Performer:  ${bestPerformer.symbol} (${fmtChange(bestPerformer.change)})
Worst Performer: ${worstPerformer.symbol} (${fmtChange(worstPerformer.change)})
Performance Gap: ${perfGap}%

Average RSI:     ${fmt(avgRSI, 1)}
Overbought:      ${overbought.length > 0 ? overbought.map(s => s.symbol).join(', ') : 'None'}
Oversold:        ${oversold.length > 0 ? oversold.map(s => s.symbol).join(', ') : 'None'}
Sectors Covered: ${sectors.join(', ') || 'N/A'}

═══════════════════════════════════════════════════
MOMENTUM RANKING (by % change today)
═══════════════════════════════════════════════════
${comparison.map((s, i) =>
  `${i + 1}. ${s.symbol.padEnd(6)} ${fmtChange(s.change).padEnd(10)} | RSI: ${String(s.rsi).padEnd(7)} ${rsiSignal(s.rsi)}`
).join('\n')}

═══════════════════════════════════════════════════
QUICK VERDICT
═══════════════════════════════════════════════════
${comparison.map(s => {
  const signals = [];
  if (s.rsi !== 'N/A') {
    const r = parseFloat(s.rsi);
    if (r > 70)      signals.push('⚠️ Overbought — potential pullback');
    else if (r < 30) signals.push('✅ Oversold — potential bounce');
    else if (r >= 50)signals.push('✅ Bullish momentum');
    else             signals.push('⚠️ Weakening momentum');
  }
  if (s.change > 1)       signals.push('📈 Strong daily gain');
  else if (s.change < -1) signals.push('📉 Significant daily loss');
  const pctOfHigh = s.fiftyTwoWeekHigh > 0 ? (s.price / s.fiftyTwoWeekHigh) * 100 : 0;
  if (pctOfHigh > 90)     signals.push('🔥 Near 52-week high');
  else if (pctOfHigh < 30)signals.push('💡 Near 52-week low — value zone');
  return `${s.symbol}: ${signals.join(' | ') || 'Insufficient data'}`;
}).join('\n')}
`;

return {
  json: {
    response: formatted,
    comparison,
    bestPerformer: bestPerformer.symbol,
    worstPerformer: worstPerformer.symbol,
    perfGap: parseFloat(perfGap),
    avgRSI: parseFloat(fmt(avgRSI, 1)),
    overbought: overbought.map(s => s.symbol),
    oversold: oversold.map(s => s.symbol),
    stockCount: comparison.length
  }
};

// Dynamic sector stock seeding with known fallback data
// Get Quote will enrich with live prices, sector, industry, marketcap, CEO etc.
const sectorData = {
  'Technology': [
    { ticker: 'AAPL', knownIndustry: 'Consumer Electronics', knownMarketCap: 3665126494685, knownCeo: 'Mr. Timothy D. Cook', knownEmployees: 166000, knownBeta: 1.093, knownPeRatio: 33.20 },
    { ticker: 'MSFT', knownIndustry: 'Software - Infrastructure', knownMarketCap: 3461+1234567890, knownCeo: 'Mr. Satya Nadella', knownEmployees: 228000, knownBeta: 0.89, knownPeRatio: 34.5 },
    { ticker: 'NVDA', knownIndustry: 'Semiconductors', knownMarketCap: 4586+1234567890, knownCeo: 'Mr. Jensen Huang', knownEmployees: 29600, knownBeta: 1.68, knownPeRatio: 52.3 },
    { ticker: 'GOOGL', knownIndustry: 'Internet Content & Information', knownMarketCap: 2065+1234567890, knownCeo: 'Mr. Sundar Pichai', knownEmployees: 182502, knownBeta: 1.04, knownPeRatio: 24.8 },
    { ticker: 'META', knownIndustry: 'Social Media', knownMarketCap: 1674+1234567890, knownCeo: 'Mr. Mark Zuckerberg', knownEmployees: 86482, knownBeta: 1.21, knownPeRatio: 28.7 }
  ],
  'Healthcare': [
