  epsBasic:         inc.eps_basic,
  epsDiluted:       inc.eps_diluted,
  revenueGrowthYoY: `${revenueGrowth}%`,
  netIncomeGrowthYoY: `${netIncomeGrowth}%`,
  rd:               inc.operating_expense?.research_and_development
};

// ── 30-DAY PRICE HISTORY ────────────────────────────
const priceHistory = data.values.map(d => ({
  date:       d.datetime,
  close:      parseFloat(d.close),
  volume:     parseInt(d.volume),
  rsi:        parseFloat(d.rsi),
  macd:       parseFloat(d.macd),
  upperBand:  parseFloat(d.upper_band),
  lowerBand:  parseFloat(d.lower_band)
}));

// ── FORMATTED PROMPT FOR AI ─────────────────────────
const formattedData = `
