R&D Spend:        $${(fundamentals.rd / 1e9).toFixed(2)}B

═══════════════════════════════════════
30-DAY PRICE HISTORY (10 Most Recent)
═══════════════════════════════════════
${priceHistory.slice(0, 10).map(d =>
  `${d.date}: Close $${d.close} | RSI ${d.rsi} | Vol ${d.volume?.toLocaleString()}`
).join('\n')}
`;

return {
  json: {
    ticker:        quote.symbol,
    formattedData: formattedData,
    quote,
    company,
    technicals,
    fundamentals,
    priceHistory,
    momentum:      { label: momentumLabel, value: momentum.toFixed(2) },
    volumeTrend:   { label: volLabel, value: volChange.toFixed(2) }
  }
};
